#include <stdio.h>
#include <stdlib.h>

int main(void){
    int count[1001] = {0};      //sorts the f array
    int n, m, *f, i, j, min;

    scanf(" %d %d", &n, &m);

    f = (int*)malloc(m*sizeof(int));

    for(i=0; i<m; scanf(" %d", &f[i]), count[f[i]]++, i++)
        ;

    j = 0;

    for(i=0; i<1001; i++){
        for(; count[i]>0; f[j]=i, count[i]--, j++)
            ;
    }

    min = f[n-1] - f[0];

    for(i=1; i<=(m-n); i++)
        if((f[n+i-1] - f[i]) < min)
            min = (f[n+i-1] - f[i]);

    printf("%d\n", min);

    return 0;
}

