use std::io;

fn main(){
    let mut input = String::new();

    io::stdin().read_line(&mut input)
        .expect("read_line error");

    let n : Vec<_> = input.trim().split_ascii_whitespace()
        .map(|num| {
            num.parse::<usize>()
                .expect("Parsing error")
        }).collect();

    input.clear();
    io::stdin().read_line(&mut input)
        .expect("read_line error");

    let mut v : Vec<_> = input.trim().split_ascii_whitespace()
        .map(|num| {
            num.parse::<i32>()
                .expect("Parsing error")
        }).collect();

    v.sort();
    let mut best = v[n[1] - 1] - v[0];
    for i in 0 .. n[1] - n[0] + 1{
        best = if v[i + n[0] -1] - v[i] < best { v[i + n[0] -1] - v[i] } else { best};
    } 

    println!("{}", best);
}
